import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const BG_IMG = "data:image/jpeg;base64,";

export default function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPass, setShowPass] = useState(false);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const res = await fetch('http://localhost:5000/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password }),
      });
      const data = await res.json();
      if (!res.ok) {
        setError(data.message || 'Login failed');
      } else {
        localStorage.setItem('token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));
        navigate('/dashboard');
      }
    } catch (err) {
      setError('Server error: ' + err.message);
    }
    setLoading(false);
  };

  return (
    <>
      <style>{styles}</style>
      <div className="pg-root" style={{ backgroundImage: 'url(' + BG_IMG + ')' }}>
        <div className="pg-overlay" />
        <div className="pg-card">
          <div className="pg-brand">
            <div className="pg-brand-icon">💰</div>
            <div className="pg-brand-name">FinanceTracker</div>
          </div>
          <div className="pg-heading">Welcome back</div>
          <div className="pg-sub">Sign in to manage your finances</div>
          {error && <div className="pg-err">⚠️ {error}</div>}
          <form onSubmit={handleLogin}>
            <div className="pg-field">
              <label className="pg-label">Email</label>
              <input className="pg-input" type="email" placeholder="you@example.com"
                value={email} onChange={e => setEmail(e.target.value)} required />
            </div>
            <div className="pg-field">
              <label className="pg-label">Password</label>
              <div className="pg-wrap">
                <input className="pg-input" type={showPass ? 'text' : 'password'}
                  placeholder="Enter your password" style={{ paddingRight: 40 }}
                  value={password} onChange={e => setPassword(e.target.value)} required />
                <button type="button" className="pg-eye" onClick={() => setShowPass(!showPass)}>
                  {showPass ? '🙈' : '👁️'}
                </button>
              </div>
            </div>
            <div className="pg-forgot-row"><a className="pg-forgot">Forgot password?</a></div>
            <button className="pg-btn" type="submit" disabled={loading}>
              {loading ? 'Signing in...' : 'Sign In'}
            </button>
          </form>
          <div className="pg-divider"><span>or continue with</span></div>
          <div className="pg-social">
            <button className="pg-sbtn">🍎 Apple</button>
            <button className="pg-sbtn">
              <svg width="14" height="14" viewBox="0 0 24 24">
                <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
                <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
                <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"/>
                <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/>
              </svg>
              Google
            </button>
          </div>
          <div className="pg-foot">
            Don't have an account? <a onClick={() => navigate('/signup')}>Sign up free</a>
          </div>
        </div>
      </div>
    </>
  );
}

const styles = `
@import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600;700;800&display=swap');
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

.pg-root {
  min-height: 100vh; width: 100vw;
  display: flex; align-items: center; justify-content: center;
  font-family: 'Outfit', sans-serif;
  background-size: cover; background-position: center; background-repeat: no-repeat;
  position: relative;
}
.pg-overlay {
  position: absolute; inset: 0;
  background: rgba(255,255,255,0.3);
  backdrop-filter: blur(6px);
  -webkit-backdrop-filter: blur(6px);
}
.pg-card {
  position: relative; z-index: 10;
  width: 100%; max-width: 360px; margin: 16px;
  background: rgba(255,255,255,0.93);
  border: 1px solid rgba(255,255,255,0.9);
  border-radius: 20px; padding: 28px 28px 22px;
  box-shadow: 0 20px 70px rgba(0,0,0,0.13), 0 0 0 1px rgba(255,255,255,0.6) inset;
}
.pg-brand { display: flex; align-items: center; gap: 8px; margin-bottom: 18px; }
.pg-brand-icon {
  width: 30px; height: 30px; border-radius: 8px;
  background: #3b82f6;
  display: flex; align-items: center; justify-content: center; font-size: 15px;
}
.pg-brand-name { font-size: 15px; font-weight: 700; color: #0f172a; }
.pg-heading { font-size: 20px; font-weight: 800; color: #0f172a; margin-bottom: 3px; }
.pg-sub { font-size: 12px; color: #64748b; margin-bottom: 18px; }
.pg-err {
  padding: 9px 12px; border-radius: 8px; margin-bottom: 12px;
  background: #fef2f2; border: 1px solid #fecaca;
  font-size: 12px; color: #dc2626;
}
.pg-field { margin-bottom: 11px; }
.pg-label { display: block; font-size: 11px; font-weight: 600; color: #64748b; margin-bottom: 5px; }
.pg-wrap { position: relative; }
.pg-input {
  width: 100%; padding: 10px 13px;
  background: #f8fafc; border: 1.5px solid #e2e8f0;
  border-radius: 9px; font-size: 13px; font-family: 'Outfit', sans-serif;
  color: #0f172a; outline: none;
  transition: border-color .2s, background .2s, box-shadow .2s;
}
.pg-input::placeholder { color: #c0cce0; }
.pg-input:focus { border-color: #3b82f6; background: #fff; box-shadow: 0 0 0 3px rgba(59,130,246,0.1); }
.pg-eye {
  position: absolute; right: 11px; top: 50%; transform: translateY(-50%);
  background: none; border: none; cursor: pointer; font-size: 13px; color: #94a3b8;
}
.pg-forgot-row { text-align: right; margin-bottom: 14px; margin-top: -4px; }
.pg-forgot { font-size: 11px; color: #3b82f6; cursor: pointer; text-decoration: none; font-weight: 500; }
.pg-btn {
  width: 100%; padding: 11px;
  background: #3b82f6; border: none; border-radius: 25px;
  font-size: 13px; font-weight: 700; font-family: 'Outfit', sans-serif;
  color: #fff; cursor: pointer;
  box-shadow: 0 3px 14px rgba(59,130,246,0.35);
  transition: background .15s, transform .15s;
}
.pg-btn:hover:not(:disabled) { background: #2563eb; transform: translateY(-1px); }
.pg-btn:disabled { opacity: .6; cursor: not-allowed; }
.pg-divider { display: flex; align-items: center; gap: 10px; margin: 14px 0; }
.pg-divider::before, .pg-divider::after { content: ''; flex: 1; height: 1px; background: #e2e8f0; }
.pg-divider span { font-size: 11px; color: #94a3b8; }
.pg-social { display: flex; gap: 8px; }
.pg-sbtn {
  flex: 1; display: flex; align-items: center; justify-content: center; gap: 6px;
  padding: 9px; background: #fff; border: 1.5px solid #e2e8f0;
  border-radius: 25px; font-size: 12px; font-weight: 600; font-family: 'Outfit', sans-serif;
  color: #0f172a; cursor: pointer; transition: border-color .15s, background .15s;
}
.pg-sbtn:hover { border-color: #3b82f6; background: #f8fafc; }
.pg-foot { text-align: center; font-size: 12px; color: #94a3b8; margin-top: 16px; }
.pg-foot a { color: #3b82f6; font-weight: 600; cursor: pointer; text-decoration: none; }
.pg-foot a:hover { text-decoration: underline; }
`;